it for the document to be ready\n//         var image_single = document.querySelector(\".my img\").getAttribute(\'src\'); // Use \'src\' instead of \'href\' for images\n//         document.getElementById(\"reg-img-id\").setAttribute(\'src\', image_single);\n//     });\n</script>	\n\n\";s:11:\"custom_html\";s:2302:\"<script>\n    // Get all elements with the specified class\n    var certificateLinks = document.getElementsByClassName(\"btn-blue\");\n\n    // Check if there are elements with the specified class\n    if (certificateLinks.length > 0) {\n        // Change the text content of the first matching element\n        certificateLinks[0].textContent = \"Generate Certificate\";\n    }\n</script>  \n\n\n<script>\n function work() {\n    var ischeck = document.querySelector(\'.rtec-success-message.tribe-events-notices.rtec-scrollto\');\n    if (ischeck !== null) {\n        document.querySelector(\'.tribe-events-single-event-description.tribe-events-content iframe\').style.display = \'block\';\n        \n        // Clear the interval when the condition is met\n        clearInterval(intervalId);\n    } else {\n        document.querySelector(\'.tribe-events-single-event-description.tribe-events-content iframe\').style.display = \'none\';\n    }\n}\n\nvar intervalId; // Declare the variable to store the interval ID\n\ndocument.addEventListener(\"DOMContentLoaded\", function () {\n    // Find the form by its ID\n    var form = document.getElementById(\"rtec-form\");\n\n    form.addEventListener(\"submit\", function (event) {\n        event.preventDefault();\n\n        // Set up the interval and store the ID\n        intervalId = setInterval(function () {\n            work();\n        }, 3000);\n    });\n});\n// Check if the class \'rtec-form-1\' is not available\nif (!document.querySelector(\'.rtec-form-1\')) {\n    // Select all elements matching the specified CSS selector\n    const elements = document.querySelectorAll(\'.tribe-events-single-event-description.tribe-events-content iframe\');\n\n    // Loop through each matching element\n    elements.forEach(element => {\n        // Set display to block\n        element.style.display = \'block\';\n    });\n}\n \n  \ndocument.addEventListener(\'DOMContentLoaded\', function() {\n    var originalText = \'Some text before the lost password form\';\n    var modifiedText = \'Your modified text before the lost password form\';\n    var targetElement = document.querySelector(\'.lost_password_before_form\'); // Adjust the selector based on the actual class or ID of the element\n\n    if (targetElement && targetElement.textContent.trim() === originalText) {\n        targetElement.textContent = modifiedText;\n    }\n});\n\n</script>   \";s:8:\"of_reset\";s:0:\"\";s:9:\"of_backup\";s:0:\"\";s:11:\"of_transfer\";s:0:\"\";s:11:\"white_label\";i:0;s:22:\"white_label_theme_name\";s:0:\"\";s:28:\"white_label_theme_screenshot\";s:0:\"\";s:22:\"white_label_theme_icon\";s:0:\"\";s:22:\"white_label_login_icon\";s:0:\"\";s:33:\"header_tax_wp_pattern_category_id\";s:12:\"__defaults__\";s:35:\"titlebar_tax_wp_pattern_category_id\";s:12:\"__defaults__\";s:34:\"content_tax_wp_pattern_category_id\";s:12:\"__defaults__\";s:34:\"sidebar_tax_wp_pattern_category_id\";s:12:\"__defaults__\";s:33:\"footer_tax_wp_pattern_category_id\";s:12:\"__defaults__\";}','yes');
