le\";s:65:\"kadence-cloud-surecart-license/kadence-cloud-surecart-license.php\";}i:20;a:16:{s:4:\"slug\";s:28:\"kadence-build-child-defaults\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:28:\"kadence-build-child-defaults\";s:9:\"main_file\";s:32:\"kadence-build-child-defaults.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"1.0.9\";s:12:\"release_date\";s:10:\"2024-12-16\";s:9:\"changelog\";s:70:\"* Fix: Fixing an issue with a temp folder causing issues with exports.\";s:4:\"name\";s:27:\"Kadence Child Theme Builder\";s:11:\"description\";s:44:\"Build a custom child theme with demo import.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:7:\"Kadence\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:26:\"https://www.kadencewp.com/\";s:11:\"plugin_file\";s:61:\"kadence-build-child-defaults/kadence-build-child-defaults.php\";}i:21;a:16:{s:4:\"slug\";s:16:\"kadence-shop-kit\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:3:\"pro\";s:7:\"top_dir\";s:16:\"kadence-shop-kit\";s:9:\"main_file\";s:20:\"kadence-shop-kit.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"3.0.0\";s:12:\"release_date\";s:10:\"2026-05-11\";s:9:\"changelog\";s:2276:\"* Feature: Integrate with Nexcess Licensing and Portal.\n* Feature: Account Pages module for adding and managing pages in the WooCommerce \"My Account\" area.\n* Feature: Bundled Products module for grouping products as a bundle with optional discounts and an \"Add All to Cart\" button.\n* Feature: Custom Fields for Variations module for adding custom fields to product variations.\n* Feature: Delivery Slots module for letting customers select a delivery slot for their order.\n* Feature: Image Swap module for enhancing catalog images with hover and click effects.\n* Feature: Linked Variations module for linking separate products together as visual variations.\n* Feature: Optimized Checkout module for a modern, distraction-free multi-step WooCommerce checkout.\n* Feature: Product Configurator module. Easily create unlimited product combinations with layered, attribute-based images and let customers preview their customised product in real time.\n* Feature: Product Gallery: \"Click Anywhere to Open Lightbox\" option.\n* Feature: Product Gallery: Attribute Images for switching gallery images automatically when a customer selects a variation attribute.\n* Feature: Product Gallery: new \"Thumbnails Above Image\", \"3 Column Grid\", \"2 Column Grid Highlighted\", and \"3 Column Grid Highlighted\" layouts.\n* Feature: Quickview: render the full product gallery and support variable products and Show Single Variations.\n* Feature: Sales Booster module for cross-sells and order bumps that increase average order value.\n* Feature: Show Single Variations module for showing product variations as individual products in the shop catalog.\n* Feature: Variation Swatches: accordion mode to collapse attribute swatches and save space on the product page.\n* Feature: Variation Swatches: compatibility with Aelia Currency Switcher, CURCY, WOOCS, WPML/WCML, Easy WooCommerce Discounts, Price Based on Country for WooCommerce, Woo Fees and Discounts, and WooCommerce All Products for Subscriptions.\n* Feature: Variation Swatches: per-attribute and per-term fees with tax handling and a product-edit admin UI.\n* Feature: Variation Swatches: round and square swatch shape, configurable globally or per attribute.\n* Feature: Wishlists module for letting customers save and share their favorite products.\";s:4:\"name\";s:8:\"Shop Kit\";s:11:\"description\";s:99:\"With over 15 powerful modules, Kadence Shop Kit is the most robust WooCommerce extension available.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:7:\"Kadence\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:42:\"https://www.kadencewp.com/kadence-shopkit/\";s:11:\"plugin_file\";s:37:\"kadence-shop-kit/kadence-shop-kit.php\";}i:22;a:16:{s:4:\"slug\";s:20:\"restrict-content-pro\";s:4:\"kind\";s: