e\";s:43:\"learndash-elementor/learndash-elementor.php\";}i:8;a:16:{s:4:\"slug\";s:21:\"learndash-woocommerce\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:21:\"learndash-woocommerce\";s:9:\"main_file\";s:25:\"learndash_woocommerce.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"2.0.2\";s:12:\"release_date\";s:10:\"2025-07-07\";s:9:\"changelog\";s:179:\"* Fix - Resolved `_load_textdomain_just_in_time()` notice errors that showed up in Wordpress 6.8.\n* Fix - Fixed the performance issue with WooCommerce product page select2 fields.\";s:4:\"name\";s:33:\"LearnDash WooCommerce Integration\";s:11:\"description\";s:222:\"WooCommerce is the most popular shopping cart software for WordPress. Most WordPress themes are compatible with WooCommerce. This add-on allows you to sell your LearnDash created courses with the WooCommerce shopping cart.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:51:\"https://www.learndash.com/integrations/woocommerce/\";s:11:\"plugin_file\";s:47:\"learndash-woocommerce/learndash_woocommerce.php\";}i:9;a:16:{s:4:\"slug\";s:6:\"ld-tec\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:6:\"ld-tec\";s:9:\"main_file\";s:17:\"learndash-tec.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"1.0.3\";s:12:\"release_date\";s:10:\"2026-01-21\";s:9:\"changelog\";s:319:\"* Fix - Created users are now given a randomly generated password by default to resolve a PHP warning in WordPress 6.9.\n* Fix - Resolved an issue where the Course and Group fields would not show properly when editing an Event.\n* Tweak - Updated required PHP version to 7.4.\n* Tweak - Updated required WP version to 6.6.\";s:4:\"name\";s:37:\"LearnDash Events Calendar Integration\";s:11:\"description\";s:182:\"The Events Calendar (TEC) is the most popular Events platform for WordPress. This integration allows you to connect an event with a course or group and automatically enroll the user.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:59:\"https://www.learndash.com/integrations/the-events-calendar/\";s:11:\"plugin_file\";s:24:\"ld-tec/learndash-tec.php\";}i:10;a:16:{s:4:\"slug\";s:16:\"learndash-zapier\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:16:\"learndash-zapier\";s:9:\"main_file\";s:20:\"learndash_zapier.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"2.3.2\";s:12:\"release_date\";s:10:\"2026-01-21\";s:9:\"changelog\";s:345:\"* Tweak - LearnDash requirement has been updated to 4.6.0.\n* Tweak - Updated required PHP version to 7.4.\n* Tweak - Updated required WP version to 6.6.\n* Tweak - Added actions: `learndash_zapier_uninstall`.\n* Tweak - Deprecated classes: `LearnDash_Dependency_Check_LD_Zapier`.\n* Tweak - Deprecated functions: `learndash_zapier_check_dependency`.\";s:4:\"name\";s:28:\"LearnDash Zapier Integration\";s:11:\"description\";s:276:\"Zapier is a service that makes it easy for you to connect two applications without the need to know code, currently with a library of over 300 applications. Zapier calls these connections âZapsâ, and this integration lets you create Zaps that include LearnDash activities.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:58:\"https://www.learndash.com/integrations/zapier-integration/\";s:11:\"plugin_file\";s:37:\"learndash-zapier/learndash_zapier.php\";}i:11;a:16:{s:4:\"slug\";s:25:\"learndash-paidmemberships\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:25:\"learndash-paidmemberships\";s:9:\"main_file\";s:29:\"learndash-paidmemberships.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"1.3.5\";s:12:\"release_date\";s:10:\"2022-10-28\";s:9:\"changelog\";s:259:\"* Tweak - Added additional non validated email user check to sync with LD course access\n* Tweak - Updated display email confirmation message to groups associated courses\n* Fix - Fixed non validated emails getting course access\n* Fix - Fixed PHPDOC block value\";s:4:\"name\";s:42:\"LearnDash Paid Memberships Pro Integration\";s:11:\"description\";s:348:\"PaidMemberships Pro is one of the most popular free membership plugins available for WordPress with robust user statistics and reporting of membership levels. With this integration, you can create membership level access and associate the access levels to LearnDash courses. Customers are auto-enrolled into courses after signing-up for membership.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:58:\"https://www.learndash.com/integrations/paidmembershipspro/\";s:11:\"plugin_file\";s:55:\"learndash-paidmemberships/learndash-paidmemberships.php\";}i:12;a:16:{s:4:\"slug\";s:21:\"learndash-memberpress\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:21:\"learndash-memberpress\";s:9:\"main_file\";s:25:\"learndash-memberpress.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"2.2.2\";s:12:\"release_date\";s:10:\"2022-10-19\";s:9:\"changelog\";s:392:\"* Fix - Updated get live subscription of user rather than cached version.\n* Fix - Updated run expire subscription access in silent queue and update access.\n* Fix - Fixed retroactive tool on multisite installs.\n* Fix - Fixed retroactive tool resetting user access counter on each run.\n* Fix - Fixed error when deactivating plugin.\n* Fix - Fixed unregistered cron events on plugin deactivation.\";s:4:\"name\";s:33:\"LearnDash MemberPress Integration\";s:11:\"description\";s:332:\"MemberPress is a premium WordPress membership plugin that excels in memberships, grouping, coupons, reminders, reports, and more. With this integration you can create membership levels in MemberPress and associate the access levels to LearnDash courses. Customers are then auto-enrolled into courses after signing-up for membership.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:51:\"https://www.learndash.com/integrations/memberpress/\";s:11:\"plugin_file\";s:47:\"learndash-memberpress/learndash-memberpress.php\";}i:13;a:16:{s:4:\"slug\";s:23:\"learndash-gravity-forms\";s:4:\"kind\";s:6:\"plugin\";s:12:\"minimum_tier\";s:10:\"essentials\";s:7:\"top_dir\";s:23:\"learndash-gravity-forms\";s:9:\"main_file\";s:26:\"learndash_gravityforms.php\";s:10:\"wporg_slug\";N;s:7:\"version\";s:5:\"2.1.3\";s:12:\"release_date\";s:10:\"2022-10-25\";s:9:\"changelog\";s:641:\"* Fix - Updated improve LD GF select2 box styling.\n* Fix - Updated add horizontal padding to LD option input field.\n* Fix - Updated improve style of LD options select box in GF field choices.\n* Fix - Updated use entry form feed setting to make its filter hook works instead of pulling feed settings from DB.\n* Fix - Fixed editor CSS styles are broken because of jQuery UI base theme CSS.\n* Fix - Fixed undefined array index error.\n* Fix - Fixed incorrect property name is JS script.\n* Fix - Fixed JS conflict error on form edit screen.\n* Fix - Fixed selecting options in LD options select box for GF field choices close GF choices UI flyout.\";s:4:\"name\";s:35:\"LearnDash Gravity Forms Integration\";s:11:\"description\";s:257:\"Gravity Forms is hands-down the industryâs best custom form development plugin. With this integration, you can create a completely custom course registration form and associate your online courses to it so that when users register, they are auto-enrolled.\";s:8:\"category\";s:0:\"\";s:7:\"authors\";a:1:{i:0;s:9:\"LearnDash\";}s:17:\"documentation_url\";s:0:\"\";s:8:\"homepage\";s:53:\"https://www.learndash.com/integrations/gravity-forms/\";s:11:\"plugin_file\";s:50:\"learndash-gravity-forms/learndash_gravityforms.php\";